import { CCol, CForm, CFormInput, CFormTextarea, CButton, CFormLabel, CFormSelect } from "@coreui/react";
import React, { useEffect, useState } from "react";
import Select from "react-select";
import TagsInput from "react-tagsinput";
import "react-tagsinput/react-tagsinput.css";
import { v4 as uuidv4 } from 'uuid';
import { useLocation, useNavigate } from 'react-router-dom';
import { createBlog, getBlogData, updateBlog } from "src/components/services/BlogApi";
import FormInput from "src/utils/FormInput";
import TextArea from "src/utils/TextArea";
import { getEnableCategory } from "src/components/services/CategoryApi";
import UploadFiles from "src/utils/UploadFiles";
import { getRelatedTriviaByCategory } from "src/components/services/TriviaApi";
import { getRelatedInfograpicByCategory } from "src/components/services/InfrograpicApi";
import GoBackComponent from "src/utils/GoBackComponent";
import authService from "src/auth/auth.service";

const BlogForm = (props) => {
    const navigate = useNavigate();
    const location = useLocation();
    const { type } = props;
    const [formData, setFormData] = useState({ title: "", metaTitle: "", metaDescription: "", metaImageAlt: "", authorName: "", linkedin: "", pageId: uuidv4() });
    const [authorImagePath, setAuthorImagePath] = useState("");
    const [coverImage, setCoverImage] = useState();
    const [tags, setTags] = useState([]);
    const [metaKeyWords, setMetaKeywords] = useState([]);
    const [errors, setErrors] = useState("");
    const [category, setCategory] = useState({});
    const [categoriesOption, setCategoriesOption] = useState([]);
    const [isButtonDisabled, setIsButtonDisabled] = useState(false);
    const [editData, setEditData] = useState({});
    const [triviaOption, setTriviaOption] = useState([]);
    const [infographicOption, setInfographicOption] = useState([]);
    const [relatedTrivia, setRelatedTrivia] = useState([]);
    const [relatedInfographic, setRelatedInfographic] = useState([]);

    const handleChange = (event) => {
        setFormData({
            ...formData,
            [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' '),
        });
    };

    const tagsChange = (tag) => {
        setTags(tag);
    }

    const metaKeyWordsChange = (keywords) => {
        setMetaKeywords(keywords);
    };

    const handleChangeCategory = (data, type) => {
        if (type === "INFOGRAPIC") {
            setRelatedInfographic(data);
        } else if (type === "TRIVIA") {
            setRelatedTrivia(data);
        } else {
            setCategory(data)
            setRelatedInfographic([]);
            setRelatedTrivia([]);
            setTriviaOption([]);
            setInfographicOption([]);
            getTriviaOptionData(data.value);
            getInfograpicOptionData(data.value);
        }
    }

    const getTriviaOptionData = async (id, relatedTrivias) => {
        let response = await getRelatedTriviaByCategory(id);
        if (response?.code === 200) {
            response?.results && response?.results.map((data) => {
                setTriviaOption(current => [...current, { label: data.name, value: data.id }]);
            })
            if (type === "UPDATE") {
                var filteredArray = response?.results && response?.results.filter(function (n) { return relatedTrivias && relatedTrivias.indexOf(n.id) !== -1; });
                filteredArray && filteredArray.map((data) => { setRelatedTrivia(current => [...current, { label: data.name, value: data.id }]); });
            }
        }
    }

    const getInfograpicOptionData = async (id, relatedInfograpics) => {
        let response = await getRelatedInfograpicByCategory(id);
        if (response?.code === 200) {
            response?.results && response?.results.map((data) => {
                setInfographicOption(current => [...current, { label: data.name, value: data.id }]);
            })
            if (type === "UPDATE") {
                var filteredArray = response?.results && response?.results.filter(function (n) { return relatedInfograpics && relatedInfograpics.indexOf(n.id) !== -1; });
                filteredArray && filteredArray.map((data) => { setRelatedInfographic(current => [...current, { label: data.name, value: data.id }]); });
            }
        }
    }

    const uploadAddAttachments = (imagePath, logoFlag) => {
        if (logoFlag) {
            setAuthorImagePath(imagePath);
        } else {
            setCoverImage(imagePath);
        }
        setIsButtonDisabled(false);
    };

    const validateForm = () => {
        let errors = {};
        let formIsValid = true;
        var expression = /(https?:\/\/(?:www\.|(?!www))[a-zA-Z0-9][a-zA-Z0-9-]+[a-zA-Z0-9]\.[^\s]{2,}|www\.[a-zA-Z0-9][a-zA-Z0-9-]+[a-zA-Z0-9]\.[^\s]{2,}|https?:\/\/(?:www\.|(?!www))[a-zA-Z0-9]+\.[^\s]{2,}|www\.[a-zA-Z0-9]+\.[^\s]{2,})/gi;
        var urlRegex = new RegExp(expression);
        if (!formData?.title) {
            errors['title'] = "Please enter title";
            formIsValid = false;
        }
        if (!category?.value) {
            errors['category'] = "Please select category";
            formIsValid = false;
        }
        if (!formData?.metaTitle) {
            errors['metaTitle'] = "Please enter meta title";
            formIsValid = false;
        }
        if (!formData?.metaDescription) {
            errors['metaDescription'] = "Please enter meta description";
            formIsValid = false;
        }
        if (!formData?.metaImageAlt) {
            errors['metaImageAlt'] = "Please enter meta image alt";
            formIsValid = false;
        }
        if (metaKeyWords?.length == 0) {
            errors['metaKeyWords'] = "Please enter at least one keyword";
            formIsValid = false;
        }
        // if (tags?.length === 0) {
        //     errors['tags'] = "Please enter at least one tags";
        //     formIsValid = false;
        // }
        // if (!formData.authorName) {
        //     errors['authorName'] = "Please enter author name";
        //     formIsValid = false;
        // }
        if (formData.linkedin && !formData.linkedin.match(urlRegex)) {
            errors['linkedin'] = "Please enter a valid url";
            formIsValid = false;
        }
        if (!coverImage) {
            errors['coverImage'] = "Please add cover image";
            formIsValid = false;
        }
        setErrors(errors);
        setTimeout(() => {
            setErrors("");
        }, 5000);
        return formIsValid;
    };

    const onClickNext = async (event) => {
        if (validateForm()) {
            let relatedTrivias = [];
            let relatedInfograpics = [];
            relatedTrivia && relatedTrivia.map((item) => {
                relatedTrivias.push(item.value)
            })
            relatedInfographic && relatedInfographic.map((item) => {
                relatedInfograpics.push(item.value)
            })
            let postData = { "title": formData?.title?.trim(), "pageId": formData?.pageId, content: {}, "coverImage": coverImage._id, "category": category?.value, "relatedTrivias": relatedTrivias, "relatedInfograpics": relatedInfograpics, "tags": tags, };
            let metaTags = { "metaTitle": formData?.metaTitle, "metaDescription": formData?.metaDescription, "metaKeyWords": metaKeyWords, "metaImageAlt": formData?.metaImageAlt };
            let author = { "name": formData?.authorName, "linkedin": formData?.linkedin, "image": authorImagePath?._id };
            postData.metaTags = metaTags;
            postData.publisher = author;
            let data = {};
            if (props.type === "UPDATE" || location?.state?.backFromEditor) {
                data = await updateBlog(formData?.pageId, postData)
            } else {
                data = await createBlog(postData);
            }
            if (data.code === 202 || data.code === 201) {
                navigate(`/blog/page/${formData?.pageId}`, { state: { isUpdateBlogPage: props.type === "UPDATE" }})
            }
        }
    }

    const getBlogDataById = async (pageId, categories) => {
        let response = await getBlogData(pageId);
        if (response?.code === 200) {
            let blogData = response?.results;
            setEditData(blogData);
            let formData = {
                title: blogData.data?.title,
                metaTitle: blogData.data?.metaTags?.metaTitle,
                metaDescription: blogData.data?.metaTags?.metaDescription,
                metaImageAlt: blogData.data?.metaTags?.metaImageAlt,
                pageId: props.pageId || location?.state?.blogPageId,
                authorName: blogData?.publisher?.name,
                linkedin: blogData?.publisher?.linkedin
            }
            setMetaKeywords(blogData.data?.metaTags?.metaKeyWords ? blogData.data?.metaTags?.metaKeyWords : []);
            let category = categories && categories.find((data) => data.value === blogData.data?.category);
            setCategory(category);
            setTags(blogData.data?.tags);
            setCoverImage(blogData?.coverImage);
            setAuthorImagePath(blogData?.publisher?.image);
            setFormData(formData);
            getInfograpicOptionData(blogData.data?.category, blogData.data?.relatedInfograpics);
            getTriviaOptionData(blogData.data?.category, blogData.data?.relatedTrivias);
        }
    }

    const getCategory = async () => {
        let categories = [];
        let response = await getEnableCategory();
        if (response?.code === 200) {
            response?.results && response?.results.map((data) => {
                categories.push({ label: data.name, value: data._id })
            })
            setCategoriesOption(categories);
            if (props.type === "UPDATE" || location?.state?.backFromEditor) {
                getBlogDataById(props.pageId || location?.state?.blogPageId, categories);
            }
        }
    }

    const onClickBlogPreview = () => {
        window.open(`${process.env.REACT_APP_infratechURL}/blog/${editData?.data?.slug}`);
    }

    useEffect(() => {
        getCategory();
    }, [])

    return (
        <>
            <GoBackComponent goBackData={"blog"} />
            <div className='customContainer'>
                <CForm className="row g-3 needs-validation" onSubmit={(e) => e.preventDefault()}>
                    <UploadFiles
                        id={"blogCoverImage"}
                        accept=".jpg,.png,.jpeg"
                        label="Cover Image"
                        updateImage={coverImage?.imageUrl}
                        updateFilesCb={uploadAddAttachments}
                    />
                    <span style={{ color: "red", textAlign: "center" }}>{errors['coverImage']}</span>
                    <CCol md={6}>
                        <div className='form-group'>
                            <CFormLabel htmlFor="exampleFormControlTextarea1"> Select Category <span className="text-danger">*</span></CFormLabel>
                            <Select
                                placeholder={"Select type"}
                                className="wnforSelect"
                                name={"userFilterOption"}
                                options={categoriesOption}
                                value={category}
                                onChange={handleChangeCategory}
                                classNamePrefix="select"
                                styles={{
                                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                        const color = '#03a68059';
                                        return {
                                            ...styles,
                                            backgroundColor: isDisabled
                                                ? null
                                                : isSelected
                                                    ? '#03a68059'
                                                    : isFocused
                                                        ? '#03a68059'
                                                        : null,
                                            color: isDisabled
                                                ? '#ccc'
                                                : isSelected
                                                    ? color > 2
                                                        ? '#00374d'
                                                        : '#00374d'
                                                    : data.color,
                                            cursor: isDisabled ? 'not-allowed' : 'default',

                                            ':active': {
                                                ...styles[':active'],
                                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                                            },
                                        };
                                    },
                                }}
                            />
                            <span style={{ color: "red" }}>{errors['category']}</span>
                        </div>
                    </CCol>
                    <CCol md={12}>
                        <FormInput
                            value={formData.title}
                            label={"Title"}
                            name={"title"}
                            onChange={handleChange}
                            error={errors['title']}
                            required={true}
                        />
                    </CCol>
                    <hr />
                    <CCol md={8}>
                        <FormInput
                            value={formData.authorName}
                            label={"Author Name"}
                            name={"authorName"}
                            onChange={handleChange}
                        />
                        <FormInput
                            value={formData.linkedin}
                            label={"LinkedIn Link"}
                            name={"linkedin"}
                            onChange={handleChange}
                            error={errors['linkedin']}
                        />
                    </CCol>
                    <CCol md={4}>
                        <UploadFiles
                            id={"blogAuthorImage"}
                            accept=".jpg,.png,.jpeg"
                            label="Author Image"
                            updateImage={authorImagePath?.imageUrl}
                            updateFilesCb={uploadAddAttachments}
                            logoUploadFiles={true}
                        />
                    </CCol>
                    <CCol md={12}>
                        <CFormLabel> Tags <span className="text-danger">*</span></CFormLabel>
                        <TagsInput
                            value={tags}
                            onChange={tagsChange}
                            addKeys={[9, 13, 62, 188]}
                        />
                        <span style={{ color: "red" }}>{errors['tags']}</span>
                    </CCol>
                    <CCol md={12}>
                        <div className='form-group'>
                            <CFormLabel> Select Related Trivia</CFormLabel>
                            <Select
                                placeholder={"Select Related Trivia"}
                                className="wnforSelect"
                                name={"triviaFilterOption"}
                                options={triviaOption}
                                value={relatedTrivia}
                                isMulti
                                onChange={(data) => handleChangeCategory(data, "TRIVIA")}
                                classNamePrefix="select"
                                styles={{
                                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                        const color = '#03a68059';
                                        return {
                                            ...styles,
                                            backgroundColor: isDisabled
                                                ? null
                                                : isSelected
                                                    ? '#03a68059'
                                                    : isFocused
                                                        ? '#03a68059'
                                                        : null,
                                            color: isDisabled
                                                ? '#ccc'
                                                : isSelected
                                                    ? color > 2
                                                        ? '#00374d'
                                                        : '#00374d'
                                                    : data.color,
                                            cursor: isDisabled ? 'not-allowed' : 'default',

                                            ':active': {
                                                ...styles[':active'],
                                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                                            },
                                        };
                                    },
                                }}
                            />
                        </div>
                    </CCol>
                    <CCol md={12}>
                        <div className='form-group'>
                            <CFormLabel> Select Related Infographic</CFormLabel>
                            <Select
                                placeholder={"Select Related Infographic"}
                                className="wnforSelect"
                                name={"infograpicFilterOption"}
                                options={infographicOption}
                                value={relatedInfographic}
                                isMulti
                                onChange={(data) => handleChangeCategory(data, "INFOGRAPIC")}
                                classNamePrefix="select"
                                styles={{
                                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                        const color = '#03a68059';
                                        return {
                                            ...styles,
                                            backgroundColor: isDisabled
                                                ? null
                                                : isSelected
                                                    ? '#03a68059'
                                                    : isFocused
                                                        ? '#03a68059'
                                                        : null,
                                            color: isDisabled
                                                ? '#ccc'
                                                : isSelected
                                                    ? color > 2
                                                        ? '#00374d'
                                                        : '#00374d'
                                                    : data.color,
                                            cursor: isDisabled ? 'not-allowed' : 'default',

                                            ':active': {
                                                ...styles[':active'],
                                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                                            },
                                        };
                                    },
                                }}
                            />
                        </div>
                    </CCol>
                    <hr />
                    <CCol md={12}>
                        <FormInput
                            value={formData.metaTitle}
                            label={"Meta Title"}
                            name={"metaTitle"}
                            onChange={handleChange}
                            error={errors['metaTitle']}
                            required={true}
                        />
                    </CCol>
                    <CCol md={12}>
                        <TextArea
                            label={"Meta Description"}
                            name="metaDescription"
                            value={formData.metaDescription}
                            onChange={handleChange}
                            error={errors["metaDescription"]}
                            required={true}
                        />
                    </CCol>
                    <CCol md={12}>
                        <TextArea
                            label={"Meta Image Alt"}
                            name="metaImageAlt"
                            value={formData.metaImageAlt}
                            onChange={handleChange}
                            error={errors["metaImageAlt"]}
                            required={true}
                        />
                    </CCol>
                    <CCol md={12}>
                        <label>
                            {`Meta Keywords `}
                            <span className="text-danger">*</span>{" "}
                        </label>
                        <TagsInput
                            value={metaKeyWords}
                            onChange={metaKeyWordsChange}
                            addKeys={[9, 13, 62, 188]}
                        />
                        <span style={{ color: "red" }}>{errors['metaKeyWords']}</span>
                    </CCol>
                    {authService.getPermission("BLOG_UPDATE") &&
                        <CCol md={12}>
                            <CButton type="submit" color="primary" onClick={onClickNext} style={{ float: "right" }} disabled={isButtonDisabled}>
                                {"Next"}
                            </CButton>
                        </CCol>
                    }
                    {editData?.data?.status === "ENABLE" && 
                        <CCol md={12}>
                            <CButton type="submit" color="primary" onClick={onClickBlogPreview} style={{ float: "right" }}>
                                {"Preview"}
                            </CButton>
                        </CCol>
                    }
                </CForm>
            </div>
        </>
    );
};

export default BlogForm;
